sp_theme.css_variables:
/* ==========================================================
   Consumer Case Portal Theme
   Emerald + Teal Premium
   ========================================================== */

/* ---------- Brand ---------- */

$brand-primary: #0F766E;
$brand-primary-dark: #0B5D57;
$brand-primary-darker: #094A45;
$brand-primary-light: #2DD4BF;
$brand-primary-lighter: #D8FBF6;

/* ---------- Status ---------- */

$brand-success: #16A34A;
$brand-warning: #F59E0B;
$brand-danger: #DC2626;
$brand-info: #0EA5E9;

/* ---------- Background ---------- */

$body-bg: #F4FBFA;
$background-primary: #FFFFFF;
$background-secondary: #ECFDFC;
$background-tertiary: #DDF8F5;

/* ---------- Borders ---------- */

$border-primary: #C7E7E4;
$border-secondary: #DAF2EF;
$border-tertiary: #EAF8F7;

/* ---------- Typography ---------- */

$text-color: #163B39;
$text-primary: #163B39;
$text-secondary: #3B6360;
$text-tertiary: #5B7E7C;
$text-muted: #7D9C99;

/* ---------- Links ---------- */

$link-color: #0F766E;
$link-hover-color: #0B5D57;

/* ---------- Buttons ---------- */

$btn-primary-color: #FFFFFF;
$btn-primary-bg: $brand-primary;
$btn-primary-border: $brand-primary;

$btn-default-bg: #FFFFFF;
$btn-default-color: $brand-primary;
$btn-default-border: #C7E7E4;

/* ---------- Alerts ---------- */

$state-success-bg: #ECFDF5;
$state-warning-bg: #FEF3C7;
$state-danger-bg: #FEE2E2;
$state-info-bg: #DBF4FF;

$alert-success-border: #86EFAC;
$alert-warning-border: #FCD34D;
$alert-danger-border: #FCA5A5;
$alert-info-border: #7DD3FC;

/* ---------- Panels ---------- */

$panel-primary-text: #FFFFFF;
$panel-border-color: #D9EEEB;

/* ---------- Inputs ---------- */

$input-border: #C7E7E4;
$input-border-focus: #0F766E;

/* ---------- Page ---------- */

$sp-page-bg: #F4FBFA;
$sp-form-field--background-color: #FFFFFF;

/* ---------- Gray ---------- */

$gray-dark: #20403E;
$gray-darker: #16302F;
$gray: #4C6665;
$gray-light: #8FAAA8;
$gray-lighter: #F8FCFC;

/* ---------- Navbar ---------- */

$navbar-inverse-bg: #FFFFFF;
$navbar-inverse-border: #DCEFED;

$navbar-inverse-link-color: #365C58;
$navbar-inverse-link-hover-color: #0F766E;
$navbar-inverse-link-active-color: #0F766E;

$navbar-inverse-brand-color: #0F766E;

$navbar-inverse-toggle-icon-bar-bg: #0F766E;
$navbar-inverse-toggle-border-color: #C7E7E4;
